class Solution:
    def canSortArray(self, nums: List[int]) -> bool:
        # Group elements by the number of set bits
        groups = []
        current_group = []
        for num in nums:
            bits = bin(num).count('1')
            if not current_group or bin(current_group[0]).count('1') == bits:
                current_group.append(num)
            else:
                groups.append(current_group)
                current_group = [num]
        groups.append(current_group)

        # Check if each group is sorted
        for group in groups:
            if sorted(group) != group:
                return False
        return True
